#!/usr/bin/env python3
"""pain_point_survey.py — Parse survey responses and cluster by theme.
Run: python pain_point_survey.py responses.json
"""
import json
import sys
from collections import defaultdict

THEME_KEYWORDS = {
    "reporting": ["report", "dashboard", "summarize", "weekly", "monthly"],
    "document_processing": ["draft", "rfp", "contract", "review", "document"],
    "customer_support": ["ticket", "email", "customer", "inquiry", "escalation"],
    "data_lookup": ["search", "find", "query", "lookup", "retrieve"],
    "onboarding": ["onboard", "training", "new hire", "setup", "access"],
}

def classify_theme(text: str) -> str:
    text_lower = text.lower()
    for theme, keywords in THEME_KEYWORDS.items():
        if any(kw in text_lower for kw in keywords):
            return theme
    return "other"

def main(path: str) -> None:
    with open(path) as f:
        responses = json.load(f)  # list of {"participant": str, "pain_points": [str]}

    clusters: dict[str, list[dict]] = defaultdict(list)
    for resp in responses:
        for pain_point in resp["pain_points"]:
            theme = classify_theme(pain_point)
            clusters[theme].append({
                "participant": resp["participant"],
                "text": pain_point,
            })

    print(f"\nSurvey analysis — {len(responses)} participants\n")
    for theme, items in sorted(clusters.items(), key=lambda x: -len(x[1])):
        print(f"  {theme.upper()} ({len(items)} mentions)")
        for item in items[:3]:  # show top 3 per theme
            print(f"    - [{item['participant']}] {item['text'][:80]}")
        print()

if __name__ == "__main__":
    if len(sys.argv) != 2:
        print("Usage: python pain_point_survey.py <responses.json>")
        sys.exit(1)
    main(sys.argv[1])
